('Priya Sharma', 'Bachelor of Computer Science', 'The computer science program here is exceptional. The AI and machine learning courses are cutting-edge, and the career services team was incredibly supportive throughout my job search.', 5, 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=200&q=80', true, 3),
('Wei Ming', 'Diploma in Information Technology', 'Even as a diploma student, I felt fully supported. The hands-on projects gave me real-world experience that employers valued immediately after graduation.', 5, 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=200&q=80', true, 4),
